func startHealthChecker(pool *ServerPool, interval time.Duration) {
    go func() {
        t := time.NewTicker(interval)
        for {
            select {
            case <-t.C:
                log.Println("Health check starting")
                pool.HealthCheck()
                log.Println("Health check done")
            }
        }
    }()
}

